def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 3:
            penalty = 0
            for p in range(1, 6):
                sub_penalty = 0
                for q in range(1, 4):
                    sub_penalty += ((ratio / (p + q)) ** (2 * q)) / (q + 1)
                penalty += sub_penalty / p
            priorities[i] = (ratio ** 4) + penalty
        elif 1 < ratio <= 3:
            sum_exp = 0
            for x in range(1, 5):
                for y in range(1, 4):
                    term = ((-1) ** (x + y)) * (ratio ** (x * y)) / (x * y)
                    sum_exp += term
            priorities[i] = abs(sum_exp) * (20 / ratio)
            if ratio > 2.5:
                extra = 0
                for z in range(1, 5):
                    extra += ((ratio ** z) / (z ** 2)) * (np.sin(ratio * z))
                priorities[i] += abs(extra)
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 11):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                score += sign * (ratio ** j) / (j ** 0.5)
            multiplier = 25 if ratio < 0.2 else 15 if ratio < 0.5 else 8
            priorities[i] = abs(score) * multiplier
            if 0.7 < ratio <= 1:
                extra = 0
                for m in range(1, 6):
                    extra += (ratio ** m) / (m * (m + 1))
                priorities[i] += extra
        else:
            priorities[i] = 0 if item == 0 else np.inf
        if capacity > 0 and priorities[i] != np.inf:
            adjust_factor = 1
            for s in range(1, 4):
                adjust_factor += (np.log1p(capacity + s) / (s + 1))
            priorities[i] /= adjust_factor
            if priorities[i] < 0:
                priorities[i] = 0
    return priorities
